def collect_with_retry(
    batch_id: str,
    original_requests: dict[str, dict],  # {custom_id: request_params}
    max_retries: int = 2,
) -> tuple[list[dict], list[str]]:
    """
    Download results, separate successes from errors.
    Returns (successes, failed_ids_for_retry).
    """
    import anthropic
    client = anthropic.Anthropic()

    successes = []
    failed_ids = []

    for result in client.messages.batches.results(batch_id):
        if result.result.type == "succeeded":
            successes.append({
                "id":      result.custom_id,
                "content": result.result.message.content[0].text,
            })
        else:
            failed_ids.append(result.custom_id)
            print(f"Failed: {result.custom_id} — {result.result.error.type}")

    print(f"Batch {batch_id}: {len(successes)} succeeded, {len(failed_ids)} failed")
    return successes, failed_ids
